#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks_work_size) {
    (void)d_Ne;
    (void)blocks_work_size;

    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int lsize = (int)get_local_size(0);

    int start = bx * lsize;
    int nf = (int)(d_no - (long)start);
    if (nf <= 0) return;
    if (nf > lsize) nf = lsize;

    if (tx == 0) {
        fp sum = 0.0f;
        fp sum2 = 0.0f;
        for (int i = 0; i < nf; i++) {
            int idx = (start + i) * d_mul;
            sum += d_sums[idx];
            sum2 += d_sums2[idx];
        }
        int out = bx * d_mul * lsize;
        d_sums[out] = sum;
        d_sums2[out] = sum2;
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I) {
    (void)lambda;
    (void)Nr;

    int ei = (int)get_global_id(0);
    if ((long)ei >= Ne) return;

    int row = ei / Nc;
    int col = ei - row * Nc;

    fp Jc = d_I[ei];

    fp dN = d_I[iN[row] * Nc + col] - Jc;
    fp dS = d_I[iS[row] * Nc + col] - Jc;
    fp dW = d_I[row * Nc + jW[col]] - Jc;
    fp dE = d_I[row * Nc + jE[col]] - Jc;

    fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
    fp L  = (dN + dS + dW + dE) / Jc;

    fp num  = (fp)0.5f * G2 - (fp)0.0625f * (L * L);
    fp den  = (fp)1.0f + (fp)0.25f * L;
    fp qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
    fp c = (fp)1.0f / ((fp)1.0f + den);

    if (c < (fp)0.0f) c = (fp)0.0f;
    else if (c > (fp)1.0f) c = (fp)1.0f;

    d_dN[ei] = dN;
    d_dS[ei] = dS;
    d_dW[ei] = dW;
    d_dE[ei] = dE;
    d_c[ei] = c;
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I) {
    (void)Nr;
    (void)iN;
    (void)jW;

    int ei = (int)get_global_id(0);
    if ((long)ei >= Ne) return;

    int row = ei / Nc;
    int col = ei - row * Nc;

    fp cN = d_c[ei];
    fp cS = d_c[iS[row] * Nc + col];
    fp cW = d_c[ei];
    fp cE = d_c[row * Nc + jE[col]];

    fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
    d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
